solution:
fn main() {
    let numbers = vec![1, 2, 3, 4, 5];

    let doubled: Vec<i32> = numbers
        .iter()
        .map(|&x| x * 2)
        .collect();

    assert_eq!(doubled, vec![2, 4, 6, 8, 10]);

    let string_numbers: Vec<String> = numbers
        .iter()
        .map(|x| x.to_string())
        .collect();

    assert_eq!(string_numbers, vec!["1", "2", "3", "4", "5"]);
    println!("All tests passed!");
}
